{ yylhsminor.yy452 = createJoinTableNode(pCxt, yymsp[-4].minor.yy42, yymsp[-5].minor.yy452, yymsp[-2].minor.yy452, yymsp[0].minor.yy452); }
  yymsp[-5].minor.yy452 = yylhsminor.yy452;
        break;
      case 579: /* join_type ::= */
{ yymsp[1].minor.yy42 = JOIN_TYPE_INNER; }
        break;
      case 580: /* join_type ::= INNER */
{ yymsp[0].minor.yy42 = JOIN_TYPE_INNER; }
        break;
      case 581: /* query_specification ::= SELECT hint_list set_quantifier_opt tag_mode_opt select_list from_clause_opt where_clause_opt partition_by_clause_opt range_opt every_opt fill_opt twindow_clause_opt group_by_clause_opt having_clause_opt */
{
                                                                                    yymsp[-13].minor.yy452 = createSelectStmt(pCxt, yymsp[-11].minor.yy137, yymsp[-9].minor.yy844, yymsp[-8].minor.yy452, yymsp[-12].minor.yy844);
                                                                                    yymsp[-13].minor.yy452 = setSelectStmtTagMode(pCxt, yymsp[-13].minor.yy452, yymsp[-10].minor.yy137);
                                                                                    yymsp[-13].minor.yy452 = addWhereClause(pCxt, yymsp[-13].minor.yy452, yymsp[-7].minor.yy452);
                                                                                    yymsp[-13].minor.yy452 = addPartitionByClause(pCxt, yymsp[-13].minor.yy452, yymsp[-6].minor.yy844);
                                                                                    yymsp[-13].minor.yy452 = addWindowClauseClause(pCxt, yymsp[-13].minor.yy452, yymsp[-2].minor.yy452);
                                                                                    yymsp[-13].minor.yy452 = addGroupByClause(pCxt, yymsp[-13].minor.yy452, yymsp[-1].minor.yy844);
                                                                                    yymsp[-13].minor.yy452 = addHavingClause(pCxt, yymsp[-13].minor.yy452, yymsp[0].minor.yy452);
                                                                                    yymsp[-13].minor.yy452 = addRangeClause(pCxt, yymsp[-13].minor.yy452, yymsp[-5].minor.yy452);
                                                                                    yymsp[-13].minor.yy452 = addEveryClause(pCxt, yymsp[-13].minor.yy452, yymsp[-4].minor.yy452);
                                                                                    yymsp[-13].minor.yy452 = addFillClause(pCxt, yymsp[-13].minor.yy452, yymsp[-3].minor.yy452);
                                                                                  }
        break;
      case 582: /* hint_list ::= */
{ yymsp[1].minor.yy844 = createHintNodeList(pCxt, NULL); }
        break;
      case 583: /* hint_list ::= NK_HINT */
{ yylhsminor.yy844 = createHintNodeList(pCxt, &yymsp[0].minor.yy0); }
  yymsp[0].minor.yy844 = yylhsminor.yy844;
        break;
