      case 604: /* partition_item ::= expr_or_subquery AS column_alias */ yytestcase(yyruleno==604);
{ yylhsminor.yy452 = setProjectionAlias(pCxt, releaseRawExprNode(pCxt, yymsp[-2].minor.yy452), &yymsp[0].minor.yy129); }
  yymsp[-2].minor.yy452 = yylhsminor.yy452;
