      case 599: /* partition_by_clause_opt ::= PARTITION BY partition_list */
      case 624: /* group_by_clause_opt ::= GROUP BY group_by_list */ yytestcase(yyruleno==624);
      case 644: /* order_by_clause_opt ::= ORDER BY sort_specification_list */ yytestcase(yyruleno==644);
{ yymsp[-2].minor.yy844 = yymsp[0].minor.yy844; }
