{ yymsp[-5].minor.yy452 = createFillNode(pCxt, FILL_MODE_VALUE, createNodeListNode(pCxt, yymsp[-1].minor.yy844)); }
        break;
      case 616: /* fill_opt ::= FILL NK_LP VALUE_F NK_COMMA expression_list NK_RP */
{ yymsp[-5].minor.yy452 = createFillNode(pCxt, FILL_MODE_VALUE_F, createNodeListNode(pCxt, yymsp[-1].minor.yy844)); }
        break;
      case 617: /* fill_mode ::= NONE */
{ yymsp[0].minor.yy264 = FILL_MODE_NONE; }
        break;
      case 618: /* fill_mode ::= PREV */
{ yymsp[0].minor.yy264 = FILL_MODE_PREV; }
        break;
      case 619: /* fill_mode ::= NULL */
{ yymsp[0].minor.yy264 = FILL_MODE_NULL; }
        break;
      case 620: /* fill_mode ::= NULL_F */
{ yymsp[0].minor.yy264 = FILL_MODE_NULL_F; }
        break;
      case 621: /* fill_mode ::= LINEAR */
{ yymsp[0].minor.yy264 = FILL_MODE_LINEAR; }
