  yymsp[-2].minor.yy452 = yylhsminor.yy452;
        break;
      case 658: /* sort_specification ::= expr_or_subquery ordering_specification_opt null_ordering_opt */
{ yylhsminor.yy452 = createOrderByExprNode(pCxt, releaseRawExprNode(pCxt, yymsp[-2].minor.yy452), yymsp[-1].minor.yy178, yymsp[0].minor.yy807); }
  yymsp[-2].minor.yy452 = yylhsminor.yy452;
        break;
      case 659: /* ordering_specification_opt ::= */
{ yymsp[1].minor.yy178 = ORDER_ASC; }
        break;
      case 660: /* ordering_specification_opt ::= ASC */
{ yymsp[0].minor.yy178 = ORDER_ASC; }
        break;
      case 661: /* ordering_specification_opt ::= DESC */
{ yymsp[0].minor.yy178 = ORDER_DESC; }
        break;
      case 662: /* null_ordering_opt ::= */
{ yymsp[1].minor.yy807 = NULL_ORDER_DEFAULT; }
        break;
      case 663: /* null_ordering_opt ::= NULLS FIRST */
{ yymsp[-1].minor.yy807 = NULL_ORDER_FIRST; }
        break;
      case 664: /* null_ordering_opt ::= NULLS LAST */
{ yymsp[-1].minor.yy807 = NULL_ORDER_LAST; }
